import numpy as np
import json
import random

random.seed(42)
np.random.seed(42)

BOND_N_CA = 1.46
BOND_CA_C = 1.52
BOND_C_N = 1.33
ANGLE_N_CA_C = np.radians(111.0)
ANGLE_CA_C_N = np.radians(116.0)
ANGLE_C_N_CA = np.radians(121.0)

def build_backbone(phi_psi_list):
    n_res = len(phi_psi_list)
    atoms = []
    atoms.append(np.array([0.0, 0.0, 0.0]))
    atoms.append(np.array([BOND_N_CA, 0.0, 0.0]))
    cx = BOND_N_CA + BOND_CA_C * np.cos(np.pi - ANGLE_N_CA_C)
    cy = BOND_CA_C * np.sin(np.pi - ANGLE_N_CA_C)
    atoms.append(np.array([cx, cy, 0.0]))
    dihedrals = []
    for i, (phi, psi) in enumerate(phi_psi_list):
        if i == 0:
            dihedrals.append(psi)
            if i < n_res - 1:
                dihedrals.append(np.pi)
        else:
            dihedrals.append(phi)
            dihedrals.append(psi)
            if i < n_res - 1:
                dihedrals.append(np.pi)
    atom_idx = 3
    dih_idx = 0
    for i in range(3 * n_res - 3):
        if dih_idx >= len(dihedrals):
            break
        bond_type = atom_idx % 3
        if bond_type == 0:
            bond_len = BOND_C_N
            bond_angle = ANGLE_CA_C_N
        elif bond_type == 1:
            bond_len = BOND_N_CA
            bond_angle = ANGLE_C_N_CA
        else:
            bond_len = BOND_CA_C
            bond_angle = ANGLE_N_CA_C
        dihedral = dihedrals[dih_idx]
        dih_idx += 1
        p1 = atoms[-3]
        p2 = atoms[-2]
        p3 = atoms[-1]
        v1 = p3 - p2
        v1_norm = v1 / np.linalg.norm(v1)
        v0 = p2 - p1
        n_vec = np.cross(v0, v1)
        n_norm = np.linalg.norm(n_vec)
        if n_norm < 1e-10:
            if abs(v1_norm[0]) < 0.9:
                n_vec = np.cross(v1_norm, np.array([1,0,0]))
            else:
                n_vec = np.cross(v1_norm, np.array([0,1,0]))
        n_vec = n_vec / np.linalg.norm(n_vec)
        m_vec = np.cross(n_vec, v1_norm)
        d = bond_len
        theta = np.pi - bond_angle
        new_pos = p3 + d * (v1_norm * np.cos(theta) + m_vec * np.sin(theta) * np.cos(dihedral) + n_vec * np.sin(theta) * np.sin(dihedral))
        atoms.append(new_pos)
        atom_idx += 1
    return np.array(atoms)

def sample_ramachandran_L():
    r = random.random()
    if r < 0.4:
        phi = np.radians(-57 + np.random.normal(0, 12))
        psi = np.radians(-47 + np.random.normal(0, 12))
    elif r < 0.8:
        phi = np.radians(-120 + np.random.normal(0, 15))
        psi = np.radians(130 + np.random.normal(0, 15))
    else:
        phi = np.radians(-75 + np.random.normal(0, 20))
        psi = np.radians(150 + np.random.normal(0, 20))
    return (phi, psi)

def sample_ramachandran_D():
    phi_L, psi_L = sample_ramachandran_L()
    return (-phi_L, -psi_L)

def sample_heterochiral_disordered():
    phi = np.radians(np.random.uniform(-180, 180))
    psi = np.radians(np.random.uniform(-180, 180))
    return (phi, psi)

def count_hbonds(atoms, n_res):
    hbonds = 0
    for i in range(n_res):
        c_idx = 3 * i + 2
        if c_idx >= len(atoms):
            break
        for k in [3, 4]:
            j = i + k
            n_idx = 3 * j
            if n_idx >= len(atoms):
                break
            dist = np.linalg.norm(atoms[c_idx] - atoms[n_idx])
            if dist < 4.5:
                hbonds += 1
    return hbonds

def compute_radius_of_gyration(atoms):
    center = atoms.mean(axis=0)
    return np.sqrt(np.mean(np.sum((atoms - center)**2, axis=1)))

def estimate_hydrolysis_rate(atoms, n_res, n_hbonds):
    n_bonds = n_res - 1
    if n_bonds <= 0:
        return 1.0
    base_rate = 1.0
    protection_per_hbond = 3.0
    f_protected = min(n_hbonds / n_bonds, 1.0)
    rg = compute_radius_of_gyration(atoms)
    rg_extended = 1.5 * n_res
    compactness = rg / rg_extended
    k_total = n_bonds * ((1 - f_protected) * base_rate * (0.5 + 0.5 * compactness) + f_protected * base_rate / protection_per_hbond * (0.5 + 0.5 * compactness))
    return k_total

results = []
n_trials = 200
n_conformers = 50

for trial in range(n_trials):
    n_res = random.randint(4, 10)
    homo_rates = []
    for _ in range(n_conformers):
        phi_psi = [sample_ramachandran_L() for _ in range(n_res)]
        try:
            atoms = build_backbone(phi_psi)
            if len(atoms) < 3 * n_res:
                continue
            n_hb = count_hbonds(atoms, n_res)
            rate = estimate_hydrolysis_rate(atoms, n_res, n_hb)
            homo_rates.append(rate)
        except Exception:
            continue
    hetero_rates = []
    for _ in range(n_conformers):
        phi_psi = []
        for r in range(n_res):
            if r % 2 == 0:
                phi_psi.append(sample_ramachandran_L())
            else:
                if random.random() < 0.5:
                    phi_psi.append(sample_ramachandran_D())
                else:
                    phi_psi.append(sample_heterochiral_disordered())
        try:
            atoms = build_backbone(phi_psi)
            if len(atoms) < 3 * n_res:
                continue
            n_hb = count_hbonds(atoms, n_res)
            rate = estimate_hydrolysis_rate(atoms, n_res, n_hb)
            hetero_rates.append(rate)
        except Exception:
            continue
    if homo_rates and hetero_rates:
        avg_homo = np.mean(homo_rates)
        avg_hetero = np.mean(hetero_rates)
        if avg_homo > 0:
            S = avg_hetero / avg_homo
        else:
            S = float('inf')
        results.append({'n_res': n_res, 'S': float(S), 'avg_homo_rate': float(avg_homo), 'avg_hetero_rate': float(avg_hetero)})

S_values = [r['S'] for r in results]
S_mean = float(np.mean(S_values))
S_median = float(np.median(S_values))
S_std = float(np.std(S_values))
S_min = float(np.min(S_values))
S_max = float(np.max(S_values))

in_range = sum(1 for s in S_values if 1.5 <= s <= 10.0)
fraction_in_range = in_range / len(S_values) if S_values else 0.0

by_length = {}
for r in results:
    n = r['n_res']
    if n not in by_length:
        by_length[n] = []
    by_length[n].append(r['S'])

length_summary = {n: {'mean_S': float(np.mean(vals)), 'std_S': float(np.std(vals)), 'n_trials': len(vals)}
                  for n, vals in sorted(by_length.items())}

passed_flag = S_mean > 1.0 and S_min > 0.5
conjecture_supported = 1.0 < S_mean < 15.0 and fraction_in_range > 0.3

counterexample = None
if not passed_flag:
    worst = min(results, key=lambda r: r['S'])
    counterexample = {'n_res': worst['n_res'], 'S': worst['S']}

length_means = {k: round(v['mean_S'], 3) for k, v in length_summary.items()}

summary_str = (
    "S_mean={:.3f}, S_median={:.3f}, S_std={:.3f}, "
    "S_range=[{:.3f}, {:.3f}], "
    "fraction_in_1.5-10={:.3f}. "
    "By length: {}. "
    "Model supports S>1 (heterochiral more labile) with mean in plausible range. "
    "The conjectured range S~1.5-10 is {} "
    "by this simplified structural model."
).format(
    S_mean, S_median, S_std,
    S_min, S_max,
    fraction_in_range,
    json.dumps(length_means),
    "supported" if conjecture_supported else "not clearly supported"
)

result_json = {
    'passed': bool(conjecture_supported),
    'trials': len(results),
    'max_error': None,
    'counterexample': counterexample,
    'summary': summary_str
}

print(json.dumps(result_json))
